/**
 * Scrambled DNA Reassembly Demo
 *
 * Premise: the wire protocol is *permutation-invariant at the lane
 * level*. Scrambling the byte order of a stream does NOT change the
 * per-lane byte multiset after `settleByLane`, because lane assignment
 * is content-addressed (`byte % k`). Same bytes, different arrival
 * order, same settled lanes.
 *
 * This is the "data reshapes itself" claim made concrete:
 *
 *   - Generate 1 MB of DNA-shaped bytes (bitwise 2-bit packed, 4 bases/byte).
 *   - Fisher-Yates scramble the byte order.
 *   - Push both streams through the wire pipeline:
 *         prism → settleByLane → ingestToKnotgraph → materializeIngest
 *   - Compare:
 *         (a) raw byte identity (must differ — sanity check of the scramble)
 *         (b) per-lane byte MULTISET (must be identical after sort)
 *         (c) per-lane payload LENGTH (must be identical)
 *         (d) knotgraph block count + tuple projection (must be identical)
 *         (e) DuckDB row shape (must be identical)
 *
 * All five checks must pass, witnessing the lane-level order-invariance
 * that gives the wire its "self-assembly" property.
 *
 * Usage:
 *   cd open-source/gnosis
 *   node ./bin/gnode.js run scripts/benchmark-scrambled-dna-reassembly.ts
 */

import {
  createRawStream,
  prism,
  settleByLane,
  totalPayloadLength,
  wireToStorage,
} from '../src/prismatic-refraction';
import {
  blocksDimsEqual,
  ingestToKnotgraph,
  KNOTGRAPH_DIMS,
  type IngestContext,
  type TenantId,
} from '../src/prismatic-refraction-knotgraph';
import { materializeIngest } from '../src/prismatic-refraction-duckdb';

// ─── Deterministic RNG ───────────────────────────────────────────────

function lcg(seed: number): () => number {
  let s = seed >>> 0;
  return () => {
    s = (Math.imul(s, 1664525) + 1013904223) >>> 0;
    return s;
  };
}

// ─── DNA generation (2-bit packed, 4 bases/byte) ─────────────────────

/** Generate `n` bytes of DNA-shaped data. Each byte holds 4 bases
 *  packed 2 bits per base (A=00, C=01, G=10, T=11). Each base is
 *  drawn uniformly from {A,C,G,T}, which produces full byte-space
 *  coverage (all 256 values) and spreads across all lanes under
 *  `byte % k`. A small positional bias on the high-order base
 *  creates mild lane-occupancy imbalance without collapsing to
 *  single-byte dominance. */
function generateDnaBytes(seed: number, n: number): Uint8Array {
  const rng = lcg(seed);
  const out = new Uint8Array(n);
  for (let i = 0; i < n; i++) {
    // Use the high byte of the LCG output; LCG low bits are known-weak
    // (cycle length ≤ 4 under `& 3`).
    out[i] = (rng() >>> 24) & 0xff;
  }
  return out;
}

/** Fisher-Yates scramble. Deterministic via seeded RNG. Returns a new
 *  array; input is unchanged. */
function scramble(bytes: Uint8Array, seed: number): Uint8Array {
  const out = new Uint8Array(bytes);
  const rng = lcg(seed);
  for (let i = out.length - 1; i > 0; i--) {
    // Use high 30 bits for the modulus to dodge LCG low-bit weakness.
    const j = (rng() >>> 2) % (i + 1);
    const tmp = out[i]!;
    out[i] = out[j]!;
    out[j] = tmp;
  }
  return out;
}

// ─── Comparison helpers ──────────────────────────────────────────────

function bytesEqual(a: Uint8Array | ReadonlyArray<number>, b: Uint8Array | ReadonlyArray<number>): boolean {
  if (a.length !== b.length) return false;
  for (let i = 0; i < a.length; i++) if (a[i] !== b[i]) return false;
  return true;
}

function sortedBytesHash(payload: ReadonlyArray<number>): string {
  const sorted = [...payload].sort((x, y) => x - y);
  // FNV-1a 48-bit, hex.
  let h = 0xcbf29ce484222325n;
  const P = 0x100000001b3n;
  for (const b of sorted) {
    h = ((h ^ BigInt(b & 0xff)) * P) & 0xffffffffffffffffn;
  }
  return (h & 0xffffffffffffn).toString(16).padStart(12, '0');
}

function multisetEqual(
  a: ReadonlyArray<number>,
  b: ReadonlyArray<number>,
): boolean {
  if (a.length !== b.length) return false;
  return sortedBytesHash(a) === sortedBytesHash(b);
}

function humanBytes(n: number): string {
  if (n < 1024) return `${n} B`;
  if (n < 1024 * 1024) return `${(n / 1024).toFixed(1)} KB`;
  return `${(n / (1024 * 1024)).toFixed(1)} MB`;
}

function humanPerSec(bytes: number, ms: number): string {
  return `${humanBytes((bytes / ms) * 1000)}/s`;
}

// ─── Run ─────────────────────────────────────────────────────────────

const N = 1024 * 1024; // 1 MB
const K = 16;
const SCRAMBLE_SEED = 42;
const TENANT: TenantId = { hi: 0x1234_5678, lo: 0x9abc_def0 };
const CTX: IngestContext = {
  tenant: TENANT,
  typeTag: 0xdeadbeef,
  schemaKnotHash: 0xfacefeed,
  provenanceDid: 1,
  freshnessClock: 0,
};

console.log('# Scrambled DNA Reassembly — Wire Protocol Permutation-Invariance');
console.log('');
console.log(`Payload: ${humanBytes(N)} synthetic DNA (2-bit packed, 4 bases/byte)`);
console.log(`Lanes:   k=${K}`);
console.log(`Scramble seed: ${SCRAMBLE_SEED}`);
console.log(`Node ${process.versions.node} on ${process.platform}/${process.arch}`);
console.log('');

// ─── Stage A: Generate + scramble ────────────────────────────────────

const original = generateDnaBytes(7, N);
const scrambled = scramble(original, SCRAMBLE_SEED);

const origBytesEqualScrambled = bytesEqual(original, scrambled);
const origMultisetEqualScrambled = multisetEqual(
  Array.from(original),
  Array.from(scrambled),
);

console.log('## Sanity — the scramble actually scrambled');
console.log('');
console.log(`Byte-identity equal (orig == scrambled): **${origBytesEqualScrambled}** (expect false)`);
console.log(`Byte-multiset equal (same bytes, different order): **${origMultisetEqualScrambled}** (expect true)`);
console.log('');
console.log(`Original bytes[0..7]:  ${Array.from(original.slice(0, 8)).map((b) => b.toString(16).padStart(2, '0')).join(' ')}`);
console.log(`Scrambled bytes[0..7]: ${Array.from(scrambled.slice(0, 8)).map((b) => b.toString(16).padStart(2, '0')).join(' ')}`);
console.log('');

// ─── Stage B: Wire pipeline throughput ──────────────────────────────

function timeIt<T>(fn: () => T): { meanMs: number; result: T } {
  const ITER = 3;
  // warm-up
  fn();
  const start = performance.now();
  let r: T = fn();
  for (let i = 1; i < ITER; i++) r = fn();
  return { meanMs: (performance.now() - start) / ITER, result: r };
}

const origStream = createRawStream(Array.from(original));
const scramStream = createRawStream(Array.from(scrambled));

const prismOrig = timeIt(() => prism(origStream, K));
const prismScram = timeIt(() => prism(scramStream, K));
const settleOrig = timeIt(() => settleByLane(prismOrig.result));
const settleScram = timeIt(() => settleByLane(prismScram.result));
const ingestOrig = timeIt(() => ingestToKnotgraph(origStream, K, CTX));
const ingestScram = timeIt(() => ingestToKnotgraph(scramStream, K, CTX));
const matOrig = timeIt(() => materializeIngest(ingestOrig.result));
const matScram = timeIt(() => materializeIngest(ingestScram.result));

console.log('## Throughput (original | scrambled)');
console.log('');
console.log('| Stage               | Original           | Scrambled          |');
console.log('|---------------------|--------------------|--------------------|');
console.log(`| prism               | ${humanPerSec(N, prismOrig.meanMs).padEnd(18)} | ${humanPerSec(N, prismScram.meanMs).padEnd(18)} |`);
console.log(`| settleByLane        | ${humanPerSec(N, settleOrig.meanMs).padEnd(18)} | ${humanPerSec(N, settleScram.meanMs).padEnd(18)} |`);
console.log(`| ingestToKnotgraph   | ${humanPerSec(N, ingestOrig.meanMs).padEnd(18)} | ${humanPerSec(N, ingestScram.meanMs).padEnd(18)} |`);
const matOrigRowsPerSec = Math.round(ingestOrig.result.blocks.length / (matOrig.meanMs / 1000));
const matScramRowsPerSec = Math.round(ingestScram.result.blocks.length / (matScram.meanMs / 1000));
console.log(`| materializeIngest   | ${(matOrigRowsPerSec.toLocaleString() + ' rows/s').padEnd(18)} | ${(matScramRowsPerSec.toLocaleString() + ' rows/s').padEnd(18)} |`);
console.log('');

// ─── Stage C: Per-lane byte multiset comparison ─────────────────────

const settledOrig = settleOrig.result;
const settledScram = settleScram.result;

console.log('## Lane-level reassembly (post-settle)');
console.log('');
console.log('| Lane | Orig bytes | Scram bytes | Length match | Multiset hash (orig) | Multiset hash (scram) | Reassembled |');
console.log('|------|-----------:|------------:|:------------:|:--------------------:|:---------------------:|:-----------:|');

let allLanesReassembled = true;
let totalOrigBytes = 0;
let totalScramBytes = 0;

// Build lane-indexed maps for direct comparison (settled shards are
// already sorted by laneId).
const origByLane = new Map<number, number[]>();
const scramByLane = new Map<number, number[]>();
for (const s of settledOrig) origByLane.set(s.laneId, [...s.payload]);
for (const s of settledScram) scramByLane.set(s.laneId, [...s.payload]);

const allLanes = new Set<number>([...origByLane.keys(), ...scramByLane.keys()]);
for (const lane of [...allLanes].sort((x, y) => x - y)) {
  const o = origByLane.get(lane) ?? [];
  const s = scramByLane.get(lane) ?? [];
  totalOrigBytes += o.length;
  totalScramBytes += s.length;
  const lengthMatch = o.length === s.length;
  const hO = sortedBytesHash(o);
  const hS = sortedBytesHash(s);
  const reassembled = hO === hS;
  if (!reassembled) allLanesReassembled = false;
  console.log(
    `| ${String(lane).padStart(4)} | ${String(o.length).padStart(10)} | ${String(s.length).padStart(11)} |     ${lengthMatch ? '✓' : '✗'}      |     ${hO}     |     ${hS}     |      ${reassembled ? '✓' : '✗'}      |`,
  );
}

console.log('');
console.log(`**All lanes reassembled: ${allLanesReassembled ? 'YES' : 'NO'}**`);
console.log(`Total bytes across lanes — orig: ${totalOrigBytes}, scram: ${totalScramBytes} (expect ${N})`);
console.log('');

// ─── Stage D: Knotgraph block tuple projection ──────────────────────

const blocksOrig = ingestOrig.result.blocks;
const blocksScram = ingestScram.result.blocks;

let blockCountMatch = blocksOrig.length === blocksScram.length;
let projectionMatch = true;
const blocksMatchCount = Math.min(blocksOrig.length, blocksScram.length);
for (let i = 0; i < blocksMatchCount; i++) {
  const bO = blocksOrig[i]!;
  const bS = blocksScram[i]!;
  const tupleO = [
    bO.dims[KNOTGRAPH_DIMS.TENANT_ID_HI],
    bO.dims[KNOTGRAPH_DIMS.TENANT_ID_LO],
    bO.dims[KNOTGRAPH_DIMS.REGION_ID],
    bO.dims[KNOTGRAPH_DIMS.FIELD_0],
  ];
  const tupleS = [
    bS.dims[KNOTGRAPH_DIMS.TENANT_ID_HI],
    bS.dims[KNOTGRAPH_DIMS.TENANT_ID_LO],
    bS.dims[KNOTGRAPH_DIMS.REGION_ID],
    bS.dims[KNOTGRAPH_DIMS.FIELD_0],
  ];
  for (let j = 0; j < 4; j++) {
    if (tupleO[j] !== tupleS[j]) {
      projectionMatch = false;
      break;
    }
  }
}

console.log('## Knotgraph block projection');
console.log('');
console.log(`Block count (orig): ${blocksOrig.length}`);
console.log(`Block count (scram): ${blocksScram.length}`);
console.log(`Block count match: **${blockCountMatch}**`);
console.log('');
console.log('Per-block (tenant_hi, tenant_lo, region_id, field_0/length) tuples:');
console.log(`**Identical across original vs scrambled: ${projectionMatch}**`);
console.log('');
console.log('(The `entity_id` dim 42 differs because the payload bytes may land in different within-lane order,');
console.log(' changing the 48-bit FNV hash. The *aggregate lane shape* — tenant, region, total length — does not.)');
console.log('');

// Check full dims equality — we expect these to differ because within-lane
// payload order differs between orig and scrambled.
let fullDimsMatch = true;
for (let i = 0; i < blocksMatchCount; i++) {
  if (!blocksDimsEqual(blocksOrig[i]!, blocksScram[i]!)) {
    fullDimsMatch = false;
    break;
  }
}
console.log(`Full dim-by-dim equality across all fields: **${fullDimsMatch}** (expect false — within-lane byte order differs, so content hash differs)`);
console.log('');

// ─── Stage E: DuckDB row shape ─────────────────────────────────────

const matO = matOrig.result;
const matS = matScram.result;

console.log('## DuckDB materialization');
console.log('');
console.log(`INSERT rows (orig): ${matO.params.length}`);
console.log(`INSERT rows (scram): ${matS.params.length}`);
console.log(`Row count match: **${matO.params.length === matS.params.length}**`);

// Project (tenant_hi, tenant_lo, region_id, field_0) from each row and compare.
let rowTupleMatch = true;
const rowMatchCount = Math.min(matO.params.length, matS.params.length);
for (let i = 0; i < rowMatchCount; i++) {
  const o = matO.params[i]!;
  const s = matS.params[i]!;
  // positions: 0=hi, 1=lo, 2=region_id, 7=field_0
  if (o[0] !== s[0] || o[1] !== s[1] || o[2] !== s[2] || o[7] !== s[7]) {
    rowTupleMatch = false;
    break;
  }
}
console.log(`(tenant_hi, tenant_lo, region_id, field_0) tuple match: **${rowTupleMatch}**`);
console.log('');

// ─── Verdict ────────────────────────────────────────────────────────

const verdict =
  origMultisetEqualScrambled &&
  !origBytesEqualScrambled &&
  allLanesReassembled &&
  blockCountMatch &&
  projectionMatch &&
  rowTupleMatch &&
  !fullDimsMatch; // full dims must differ (content hash encodes within-lane order)

console.log('## Verdict');
console.log('');
if (verdict) {
  console.log('**PASS** — The wire protocol is permutation-invariant at the lane level:');
  console.log('');
  console.log('  1. Input bytes were scrambled (byte identity differs).');
  console.log('  2. Byte multiset preserved (same bytes, different order).');
  console.log('  3. Per-lane byte multisets are BIT-IDENTICAL after settle.');
  console.log('  4. Knotgraph block count and aggregate tuple projection are identical.');
  console.log('  5. DuckDB row count and tenant/region/length projection are identical.');
  console.log('  6. Entity content hash differs (encodes within-lane byte order).');
  console.log('');
  console.log('The scrambled DNA reassembles itself into the SAME lane-level shape as the');
  console.log('unscrambled original — the wire\'s content-addressed lane assignment recovers');
  console.log('the aggregate structure regardless of arrival order. Data delegated to geometry.');
} else {
  console.log('**FAIL** — At least one invariant broke. See above.');
  process.exit(1);
}
